@import '../shared/_variables.scss';

.root-container {
  display: flex;
  flex-direction: row;
  height: calc(100% - $navbar-height);
  width: 100%;
}

.maps-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  position: relative;
  width: 100%;
}

.map-grid {
  display: grid;
  width: 100%;
  height: 100%;
  grid-template-columns: 1fr 1fr;

  &.one-column {
    grid-template-columns: 1fr;
  }
}

.map-box {
  border: 1px solid black;
  box-sizing: border-box;
  height: 100%;
  position: relative;
  width: 100%;
  z-index: 1;
}

.map-box.selected {
  border: 7px solid #2491ff;
}

.map {
  height: 100%;
  width: 100%;
  z-index: 1;
}

// Styling for the actions bar above the maps
.map-actions-bar {
  background-color: rgba(0, 0, 0, 0.5);
  display: flex;
  flex-direction: row;
  height: $toolbar-height;
  position: absolute;
  width: 100%;
  z-index: 2;
}

// Styling for legend on mousehover
::ng-deep .legend:hover {
  width: 100%;
  overflow-y: scroll;
  text-overflow: ellipsis;
  height: auto;
  max-width: auto;
  max-height: 80%;
  opacity: 1;
  transition-duration: 0.8s;
}

// Setting heights for built-in leaflet styles to be able to configure relative max-height
::ng-deep .leaflet-left .leaflet-control {
  height: auto;
  max-height: 75%;
}
// Setting heights for built-in leaflet styles to be able to configure relative max-height
::ng-deep .leaflet-top {
  height: 100%;
}

// Default styling for legend
::ng-deep .legend {
  top: 40px;
  bottom: 40px;
  margin: 10px;
  font-weight: bold;
  color: solid #2491ff;
  text-align: left;
  height: auto;
  width: 65px;
  text-overflow: ellipsis;
  overflow-x: hidden;
  line-height: 18px;
  background: white;
  white-space: nowrap;
  opacity: 0.7;
  display: inline-block;
  border: 2px #aaa solid;
  border-radius: 5px;
  transition: width 0.8s;
}

// Parent legend class
::ng-deep .parentlegend {
  display: flex;
  flex-direction: column;
  height: 100%;
}

// Legend line
::ng-deep .legendline {
  white-space: nowrap;
  display: inline-block;
  text-overflow: ellipsis;
  overflow: hidden;
  width: auto;
}

// // Legend color entry
::ng-deep .legend i {
  margin-left: 8px;
}

// Legend text entry
::ng-deep .legend label {
  opacity: 0.7;
  text-overflow: ellipsis;
  overflow: hidden;
  flex: 1;
  white-space: nowrap;
  max-width: 65px;
}

// Legend header
::ng-deep .legend b {
  text-align: center;
  font-size: small;
  margin: 10px;
  margin-top: 6px;
  width: auto;
  height: 10px;
  display: flex;
  flex-direction: row;
}

.actions-bar-text {
  align-items: center;
  color: #ffffff;
  display: flex;
  font-size: 13px;
  font-weight: 500;
  margin: 8px 0px 0px 20px;
}

.draw-area-button,
.upload-area-button {
  background-color: #3367d6;
  box-shadow:
    0px 1px 5px rgba(0, 0, 0, 0.12),
    0px 2px 2px rgba(0, 0, 0, 0.2),
    0px 1px 1px rgba(0, 0, 0, 0.14);
  color: #ffffff;
  font-size: 13px;
  height: 32px;
